const repo="[REDACTED_LOCAL_PATH]";
const tp="[REDACTED_LOCAL_PATH]";
const cmds=[
  ["repo_state","git status --short --branch && git rev-parse --show-toplevel && git rev-parse HEAD && git rev-parse origin/main && git rev-list --left-right --count HEAD...origin/main && git sparse-checkout list 2>&1 || true"],
  ["roadmap","nl -ba \"$TP/02_Roadmap_16Stage_Phase_Task.md\" | sed -n '1,180p'"],
  ["taskpack_files","find \"$TP\" -maxdepth 3 -type f -not -path '*/raw/*' -not -path '*/session_history/*' | sort"],
  ["handoffs","git ls-tree -r --name-only HEAD | rg '(^|/)HANDOFF\\.md$' | rg -v '(^|/)(raw|session_history)(/|$)' | tail -n 80"],
  ["openai_tree","git ls-tree -r --name-only HEAD OpenAIDatabase | rg -v '(^|/)(raw|session_history)(/|$)' | sed -n '1,200p'"]
];
const results=await Promise.all(cmds.map(async ([name,cmd])=>{
  const r=await tools.exec_command({cmd:cmd.replaceAll("$TP",tp),workdir:repo,yield_time_ms:10000,max_output_tokens:name==="roadmap"?30000:20000});
  return {name,...r};
}));
for(const r of results){text(`## ${r.name}\nexit=${r.exit_code}\n${r.output}`)}

