`git -c core.quotePath=false ls-tree -r --name-only HEAD OpenAIDatabase | rg '(^|/)(App\\.tsx|atlasctl\\.py)$|atlasctl'`,
`git ls-files -v OpenAIDatabase | awk '{m=substr($0,1,1); c[m]++} END {for(m in c) print m,c[m]}' | sort`,
`git -c core.quotePath=false ls-tree -r --name-only HEAD OpenAIDatabase | awk -F/ '{k=$1"/"$2; c[k]++} END {for(k in c) print c[k],k}' | sort -nr | head -n 40`,
